import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Button, Badge, Form, ListGroup } from 'react-bootstrap';
import { useParams } from 'react-router-dom';
import { resourceService } from '../services/resourceService';
import { Resource, Comment } from '../types';
import Loading from '../components/Loading';
import ErrorMessage from '../components/ErrorMessage';
import { useAuth } from '../context/AuthContext';

const ResourceDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [resource, setResource] = useState<Resource | null>(null);
  const [comments, setComments] = useState<Comment[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [commentContent, setCommentContent] = useState('');
  const [submittingComment, setSubmittingComment] = useState(false);
  const { user } = useAuth();

  useEffect(() => {
    if (id) {
      fetchData();
    }
  }, [id]);

  const fetchData = async () => {
    if (!id) return;
    try {
      const data = await resourceService.getById(id);
      setResource(data.resource);
      setComments(data.comments);
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to load resource');
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = () => {
    if (resource) {
      resourceService.download(resource.id);
    }
  };

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!id || !commentContent.trim()) return;

    setSubmittingComment(true);
    try {
      const newComment = await resourceService.addComment(id, commentContent);
      setComments([...comments, newComment]);
      setCommentContent('');
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to add comment');
    } finally {
      setSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    try {
      await resourceService.deleteComment(commentId);
      setComments(comments.filter(c => c.id !== commentId));
    } catch (err: any) {
      setError(err.response?.data?.error || 'Failed to delete comment');
    }
  };

  const getFileTypeIcon = (fileType: string) => {
    if (fileType.includes('pdf')) return '📄';
    if (fileType.includes('word') || fileType.includes('document')) return '📝';
    if (fileType.includes('excel') || fileType.includes('sheet')) return '📊';
    if (fileType.includes('image')) return '🖼️';
    if (fileType === 'link') return '🔗';
    return '📁';
  };

  const canPreview = () => {
    if (!resource) return false;
    return (
      resource.file_type.includes('pdf') ||
      resource.file_type.includes('image') ||
      resource.file_type === 'link'
    );
  };

  const renderPreview = () => {
    if (!resource) return null;

    if (resource.file_type === 'link') {
      return (
        <Card className="mb-4">
          <Card.Body>
            <Card.Title>Link Resource</Card.Title>
            <Card.Text>
              This resource is a link. Click the button below to open it.
            </Card.Text>
            <Button variant="primary" onClick={() => window.open(resource.file_path, '_blank')}>
              Open Link
            </Button>
          </Card.Body>
        </Card>
      );
    }

    if (resource.file_type.includes('pdf')) {
      return (
        <Card className="mb-4">
          <Card.Body>
            <Card.Title>PDF Preview</Card.Title>
            <embed
              src={`http://localhost:3000/api/resources/${resource.id}/download`}
              type="application/pdf"
              width="100%"
              height="600px"
            />
          </Card.Body>
        </Card>
      );
    }

    if (resource.file_type.includes('image')) {
      return (
        <Card className="mb-4">
          <Card.Body className="text-center">
            <Card.Title>Image Preview</Card.Title>
            <img
              src={`http://localhost:3000/api/resources/${resource.id}/download`}
              alt={resource.title}
              className="img-fluid"
              style={{ maxHeight: '600px' }}
            />
          </Card.Body>
        </Card>
      );
    }

    return null;
  };

  if (loading) {
    return <Loading />;
  }

  if (!resource) {
    return (
      <Container className="py-4">
        <ErrorMessage message="Resource not found" />
      </Container>
    );
  }

  return (
    <Container className="py-4">
      <div className="mb-4">
        <a href={`/courses/${resource.course_id}`} className="text-decoration-none">
          ← Back to Course
        </a>
      </div>

      <ErrorMessage message={error} onClose={() => setError('')} />

      <Card className="mb-4">
        <Card.Body>
          <div className="d-flex justify-content-between align-items-start mb-3">
            <Card.Title className="mb-0">{resource.title}</Card.Title>
            <Badge bg="primary">{getFileTypeIcon(resource.file_type)} {resource.file_type.split('/')[1]}</Badge>
          </div>

          <Card.Subtitle className="mb-2 text-muted">
            Uploaded by {resource.uploader_name} • {new Date(resource.created_at).toLocaleDateString()}
          </Card.Subtitle>

          {resource.description && <Card.Text className="mt-3">{resource.description}</Card.Text>}

          {resource.tags && resource.tags.length > 0 && (
            <div className="mb-3">
              {resource.tags.map((tag, index) => (
                <Badge key={index} bg="light" text="dark" className="me-1">
                  #{tag}
                </Badge>
              ))}
            </div>
          )}

          {resource.file_type !== 'link' && (
            <Button variant="primary" onClick={handleDownload}>
              Download File
            </Button>
          )}
        </Card.Body>
      </Card>

      {canPreview() && renderPreview()}

      {/* Comments Section */}
      <Card>
        <Card.Body>
          <Card.Title className="mb-3">Comments ({comments.length})</Card.Title>

          {/* Add Comment Form */}
          <Form onSubmit={handleSubmitComment} className="mb-4">
            <Form.Group className="mb-3">
              <Form.Label>Add a Comment</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                placeholder="Write your comment..."
                value={commentContent}
                onChange={(e) => setCommentContent(e.target.value)}
                required
              />
            </Form.Group>
            <Button variant="primary" type="submit" disabled={submittingComment}>
              {submittingComment ? 'Posting...' : 'Post Comment'}
            </Button>
          </Form>

          {/* Comments List */}
          {comments.length === 0 ? (
            <p className="text-muted text-center">No comments yet. Be the first to comment!</p>
          ) : (
            <ListGroup>
              {comments.map((comment) => (
                <ListGroup.Item key={comment.id}>
                  <div className="d-flex justify-content-between">
                    <div>
                      <strong>{comment.username}</strong>
                      <small className="text-muted ms-2">
                        {new Date(comment.created_at).toLocaleString()}
                      </small>
                    </div>
                    {user && user.id === comment.user_id && (
                      <Button
                        variant="outline-danger"
                        size="sm"
                        onClick={() => handleDeleteComment(comment.id)}
                      >
                        Delete
                      </Button>
                    )}
                  </div>
                  <p className="mb-0 mt-2">{comment.content}</p>
                </ListGroup.Item>
              ))}
            </ListGroup>
          )}
        </Card.Body>
      </Card>
    </Container>
  );
};

export default ResourceDetail;
